// Log workflow error to memory_long via PostgREST.
// dmo-claw note: no Telegram path — agent retrieves errors via memory_search with category='error'.
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' };

const wf = $json.workflow || {};
const exec = $json.execution || {};
const err = exec.error || {};
const timestamp = new Date().toISOString().replace('T', ' ').slice(0, 16);

const content = `Workflow error in "${wf.name}" at ${timestamp} UTC: ${err.message || 'unknown error'}. Failed at node "${exec.lastNodeExecuted || 'n/a'}". Execution ${exec.id || 'n/a'}: ${exec.url || 'n/a'}`;

const metadata = {
  execution_id: exec.id || null,
  execution_url: exec.url || null,
  execution_mode: exec.mode || null,
  workflow_id: wf.id || null,
  workflow_name: wf.name || null,
  node_name: exec.lastNodeExecuted || null,
  error_name: err.name || null,
  error_message: err.message || null,
  error_stack: err.stack ? String(err.stack).slice(0, 2000) : null
};

await this.helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/memory_long`,
  headers,
  body: JSON.stringify({
    content,
    category: 'error',
    importance: 8,
    tags: ['error', 'workflow-failure', wf.name],
    entity_name: `workflow:${wf.name}`,
    metadata
  })
});

return [{ json: { logged: true, execution_id: exec.id, workflow: wf.name } }];
